codeExample1.code:
#include <stdio.h>

int main() {
    int x = 5, y;
    y = x++; // Postfix: y gets 5, then x becomes 6
    printf("Postfix - x: %d, y: %d\n", x, y);

    x = 5;
    y = ++x; // Prefix: x becomes 6, then y gets 6
    printf("Prefix  - x: %d, y: %d\n", x, y);
    return 0;
}

codeExample2.code:
#include <stdio.h>

int main() {
    int a = 12; // Binary: 1100
    int b = 25; // Binary: 11001

    int bitAnd = a & b; // Binary: 01000 = 8
    int bitOr = a | b;  // Binary: 11101 = 29
    int isEven = (a % 2 == 0) ? 1 : 0;

    printf("And: %d, Or: %d\n", bitAnd, bitOr);
    printf("a is %s\n", isEven ? "even" : "odd");
    return 0;
}

